      const PIX_CHAVE_DL = '42988880353'
        const PIX_NOME_DL = 'Planeprof'
          const PLANOS_DL = {
              mensal: { label: 'Mensal', valor: 9.90, desc: 'por mês', economia: '' },
                  anual: { label: 'Anual', valor: 100.00, desc: 'por ano', economia: 'Economize R$ 18,80' },
                    }

                      function gerarPayloadPixDL(chave: string, nome: string, valor: number): string {
                          const valStr = valor.toFixed(2)
                              const nomeClean = nome.substring(0, 25).padEnd(1)
                                  const merchantName = nomeClean.length > 25 ? nomeClean.substring(0, 25) : nomeClean
                                      const merchantCity = 'SAO PAULO'
                                          const txid = 'PLANEPROF' + Date.now().toString().slice(-5)
                                              function tlv(tag: string, value: string) { return tag + value.length.toString().padStart(2, '0') + value }
                                                  const pixKey = tlv('01', chave)
                                                      const merchantAccInfo = tlv('00', 'BR.GOV.BCB.PIX') + pixKey
                                                          const payload = [
                                                                tlv('00', '01'),
                                                                      tlv('26', merchantAccInfo),
                                                                            tlv('52', '0000'),
                                                                                  tlv('53', '986'),
                                                                                        tlv('54', valStr),
                                                                                              tlv('58', 'BR'),
                                                                                                    tlv('59', merchantName),
                                                                                                          tlv('60', merchantCity),
                                                                                                                tlv('62', tlv('05', txid)),
                                                                                                                      '6304',
                                                                                                                          ].join('')
                                                                                                                              let crc = 0xFFFF
                                                                                                                                  for (const char of payload) {
                                                                                                                                        crc ^= char.charCodeAt(0) << 8
                                                                                                                                              for (let i = 0; i < 8; i++) crc = crc & 0x8000 ? (crc << 1) ^ 0x1021 : crc << 1
                                                                                                                                                  }
                                                                                                                                                      return payload + (crc & 0xFFFF).toString(16).toUpperCase().padStart(4, '0')
                                                                                                                                                        }

